script:
tomorrow = frappe.utils.add_days(frappe.utils.nowdate(), 1)
events = frappe.get_all(
    "School Event",
    filters={
        "start_date": tomorrow,
        "publish": 1,
        "status": ["!=", "Cancelled"]
    },
    fields=["name", "title", "venue", "start_date"]
)
for event in events:
    event_doc = frappe.get_doc("School Event", event.name)
    recipients = []
    for participant in event_doc.participants:
        if participant.email:
            recipients.append(participant.email)
    recipients = list(set(recipients))
    if recipients:
        frappe.sendmail(
            recipients=recipients,
            subject="Event Reminder: {0}".format(event_doc.title),
            message="""Dear Participant,

This is a reminder that the event **{0}** is scheduled for **{1}**.

**Venue:** {2}

Thank you.
School Administration""".format(
                event_doc.title,
                event_doc.start_date,
                event_doc.venue
            )
        )
